// 7 slides: Por qué los odontólogos necesitan SofIA
const caption = '¿Sabías que el 68% de pacientes elige la primera clínica que le responde? 🦷\n\nSofIA trabaja 24/7 por WhatsApp: agenda citas, envía recordatorios y nunca pierde un paciente.\n\n💬 Escríbenos por DM para una demo gratuita.\n\n#OdontologíaDigital #ClínicaDental #IA #SofIADentAI #AutomatizaciónDental #WhatsAppBusiness #DentistasPerú';

return [
  { json: { slide: 1, titulo: '¿Tu clínica pierde pacientes por no responder a tiempo?', subtitulo: 'El 68% elige la primera clínica que le responde.', emoji: '🦷', caption } },
  { json: { slide: 2, titulo: 'Los pacientes mandan WhatsApp a las 10pm.', subtitulo: '¿Quién responde por ti cuando cierras la clínica?', emoji: '📱', caption } },
  { json: { slide: 3, titulo: 'SofIA responde 24/7 por WhatsApp.', subtitulo: 'Agenda citas, resuelve dudas y filtra pacientes — incluso mientras duermes.', emoji: '🤖', caption } },
  { json: { slide: 4, titulo: 'Menos no-shows, más ingresos.', subtitulo: 'Recordatorios automáticos 24h antes. Confirmación de asistencia sin llamadas.', emoji: '📅', caption } },
  { json: { slide: 5, titulo: 'Tu reputación crece sola.', subtitulo: 'Encuestas NPS automáticas post-cita que generan reseñas positivas en Google.', emoji: '⭐', caption } },
  { json: { slide: 6, titulo: 'Clínicas con SofIA ven +40% en citas agendadas.', subtitulo: 'Sin contratar más personal. Solo automatizando lo que ya hacías a mano.', emoji: '📈', caption } },
  { json: { slide: 7, titulo: '¿Listo para una asistente IA en tu clínica?', subtitulo: 'Escríbenos por DM y accede a la demo gratuita. 👇', emoji: '✨', caption } }
];

// Guardar slide index y poll_url para recuperar la imagen
const placid = $input.first().json;
return [{ json: { poll_url: placid.poll_url, image_url: placid.image_url || null, status: placid.status } }];

// Agregar los 7 container IDs y armar el payload del carousel
const items = $input.all();
const containerIds = items.map(i => i.json.id).filter(Boolean);

if (containerIds.length < 2) {
  throw new Error('Se necesitan al menos 2 slides. Solo se generaron: ' + containerIds.length);
}

const caption = '¿Sabías que el 68% de pacientes elige la primera clínica que le responde? 🦷\n\nSofIA trabaja 24/7 por WhatsApp: agenda citas, envía recordatorios y nunca pierde un paciente.\n\n💬 Escríbenos por DM para una demo gratuita.\n\n#OdontologíaDigital #ClínicaDental #IA #SofIADentAI #AutomatizaciónDental #WhatsAppBusiness #DentistasPerú';

return [{ json: { children: containerIds.join(','), caption, count: containerIds.length } }];

